import boto3
from botocore.exceptions import ClientError

# Option 1: Use AWS profile (recommended for demo)
session = boto3.Session(profile_name='demo-profile')
s3_client = session.client('s3')

# Option 2: Use environment variables
# Set these before running: AWS_ACCESS_KEY_ID and AWS_SECRET_ACCESS_KEY
# s3_client = boto3.client('s3')

bucket_name = 'demo-bucket'

try:
    response = s3_client.list_objects_v2(Bucket=bucket_name)
    
    if 'Contents' in response:
        print(f"Files in {bucket_name}:")
        for obj in response['Contents']:
            print(f"  - {obj['Key']} ({obj['Size']} bytes)")
    else:
        print(f"No files found in {bucket_name}")
        
except ClientError as e:
    print(f"Error: {e}")